194	    contextLines.push(`- Regular clients: ${clients}`);
195	    contextLines.push(`- Payment terms: ${(memory.payment_terms as string) || 'not set'}`);
196	    if (memory.notes) contextLines.push(`- Notes: ${memory.notes}`);
197	
198	    const userContextBlock = `USER CONTEXT (use this to personalise every response — do not repeat it back verbatim):\n${contextLines.join('\n')}`;
199	    const systemPrompt = `${KIRA_SYSTEM_PROMPT}\n\n${userContextBlock}`;
