201	    const openaiResponse = await fetch("https://api.openai.com/v1/chat/completions", {
202	      method: "POST",
203	      headers: {
204	        "Authorization": `Bearer ${Deno.env.get("OPENAI_API_KEY")}`,
205	        "Content-Type": "application/json",
206	      },
207	      body: JSON.stringify({
208	        model: "gpt-4o-mini",
209	        max_tokens: 1000,
210	        stream: true,
211	        messages: [
212	          { role: "system", content: systemPrompt },
213	          ...conversationHistory,
214	          { role: "user", content: sanitizedPrompt }
215	        ],
216	      }),
217	    });
218	
219	    if (!openaiResponse.ok) {
220	      throw new Error("OpenAI API error: " + openaiResponse.status);
221	    }
222	
223	    // Parse OpenAI SSE stream and pipe plain text tokens to the client
224	    const { readable, writable } = new TransformStream<Uint8Array, Uint8Array>();
225	    const writer = writable.getWriter();
226	    const encoder = new TextEncoder();
227	
228	    const pump = async () => {
229	      const reader = openaiResponse.body!.getReader();
230	      const decoder = new TextDecoder();
231	      try {
232	        while (true) {
233	          const { done, value } = await reader.read();
234	          if (done) break;
235	          const chunk = decoder.decode(value, { stream: true });
236	          for (const line of chunk.split('\n')) {
