253	    pump();
254	
255	    return new Response(readable, {
256	      headers: {
257	        ...cors,
258	        'Content-Type': 'text/plain; charset=utf-8',
259	        'Cache-Control': 'no-cache',
260	        'X-Accel-Buffering': 'no',
261	      },
262	    });
263	
264	  } catch (error: unknown) {
265	    const msg = error instanceof Error ? error.message : String(error);
266	    console.error("Function Error:", msg);
267	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
268	      status: 500, headers: cors
269	    });
270	  }
271	});
