30	function isPromptAbuse(content: string): boolean {
31	  const abusePatterns = [
32	    /ignore (all |previous |above )?instructions/i,
33	    /you are now/i,
34	    /pretend (you are|to be)/i,
35	    /act as (a |an )?/i,
36	    /forget (your |all )?instructions/i,
37	    /system prompt/i,
38	    /jailbreak/i,
39	    /DAN mode/i,
40	  ];
41	  return abusePatterns.some(pattern => pattern.test(content));
42	}
